namespace BgControls.Windows.Input.Touch;/// <summary>/// 定义滑动惯性提供者的接口，用于计算触控滑动后的惯性表现./// </summary>internal interface ISwipeInertiaProvider{    /// <summary>    /// 根据捕获的一系列触摸点及其对应的时间戳，计算并获取滑动惯性参数.    /// </summary>    /// <param name="timePoints">记录了时间与位置坐标对应关系的触摸轨迹列表.</param>    /// <returns>计算得出的滑动惯性参数实例.</returns>    SwipeInertiaParams GetInertiaParams(IList<Tuple<DateTime, Point>> timePoints);}